css:
.loader {
  color: var(--loader-color, #8b5cf6);
  --loader-secondary-color: #c4b5fd;
  --loader-bg: #ffffff;
width: 60px;
aspect-ratio: 4;
background: radial-gradient(circle closest-side,currentColor 90%,#0000) 0/calc(100%/3) 100% no-repeat;
animation: l2 1s steps(3) infinite;
}
@keyframes l2 {to{background-position: 150%}}
